图形渲染管线第一部分是顶点着色器(Vertex Shader) 接受顶点作为输入 假设我们已经有了三角形的顶点坐标 12345float vertices[] = { -0.5f, -0.5f, 0.0f, 0.5f, -0.5f, 0.0f, 0.0f, 0.5f, 0.0f}; 我们需要把这些点的坐标输入给Vertex Shader 管理输入 Vertex Shader 会在GPU中分配内存来存储（或者说先开辟内存，然后copy这些顶点数据到内存中） C++中用指针来管理内存，OpenGL规范中用 Vertex Buffer Objects（VBO）来管理顶点数据的内存。 它会在GPU内存（通常被称为显存）中储存大量顶点。使用这些缓冲对象的好处是我们可以一次性的发送一大批数据到显卡上，而不是每个顶点发送一次。从CPU把数据发送到显卡相对较慢，所以只要可能我们都要尝试尽量一次性发送尽可能多的数据。当数据发送至显卡的内存中后，顶点着色器几乎能立即访问顶点，这是个非常快的过程。 OpenGL用不同的id来区分不同的对象（id通常是unsigned int） 12unsigned int VBO;glGenBuffers(1, &amp;VBO);//OpenGL generate buffer objects 现在VBO这个id已经指向了一个缓存对象但是他实际上并不是我们想要的Vertex Buffer Objects（因为未指定类型） 现在我们要给OpenGL Context说明VBO的缓存对象的类型，VBO的缓存对象类型是(GL_ARRAY_BUFFER) 1glBindBuffer(GL_ARRAY_BUFFER, VBO); // OpengL bind buffer Objects 从这一刻起，我们使用的任何（在GL_ARRAY_BUFFER目标上的）缓冲调用都会用来配置当前绑定的缓冲(VBO)。然后我们可以调用glBufferData函数，它会把之前定义的顶点数据复制到缓冲的内存中 1glBufferData(GL_ARRAY_BUFFER, sizeof(vertices), vertices, GL_STATIC_DRAW); 现在管线的输入弄好了 Vertex Shader 现在，我们暂时将顶点着色器的源代码硬编码在代码文件顶部的C风格字符串中： 123456const char *vertexShaderSource = "#version 330 core
" "layout (location = 0) in vec3 aPos;
" "void main()
" "{
" " gl_Position = vec4(aPos.x, aPos.y, aPos.z, 1.0);
" "}\0"; 为了能够让OpenGL使用它，我们必须在运行时动态编译它的源代码。 我们首先要做的是创建一个着色器对象，注意还是用ID来引用的。所以我们储存这个顶点着色器为unsigned int，然后用glCreateShader创建这个着色器 12unsigned int vertexShader;vertexShader = glCreateShader(GL_VERTEX_SHADER); 我们把需要创建的着色器类型以参数形式提供给glCreateShader。由于我们正在创建一个顶点着色器，传递的参数是GL_VERTEX_SHADER。 下一步我们把这个着色器源码附加到着色器对象上，然后编译它： 12glShaderSource(vertexShader, 1, &amp;vertexShaderSource, NULL);glCompileShader(vertexShader); Fragment Shader也是类似的 Shader Program Object 现在我们弄好了Vertex Shader 以及 Fragment Shader 但是Open GL 的Shader是用Shader Program Object来操作的 着色器程序对象(Shader Program Object)是多个着色器合并之后并最终链接完成的版本。如果要使用刚才编译的着色器我们必须把它们链接(Link)为一个着色器程序对象，然后在渲染对象的时候激活这个着色器程序。已激活着色器程序的着色器将在我们发送渲染调用的时候被使用。 当链接着色器至一个程序的时候，它会把每个着色器的输出链接到下个着色器的输入。当输出和输入不匹配的时候，你会得到一个连接错误。 创建一个程序对象很简单： 12unsigned int shaderProgram;shaderProgram = glCreateProgram(); glCreateProgram函数创建一个程序，并返回新创建程序对象的ID引用。现在我们需要把之前编译的着色器附加到程序对象上，然后用glLinkProgram链接它们： 123glAttachShader(shaderProgram, vertexShader);glAttachShader(shaderProgram, fragmentShader);glLinkProgram(shaderProgram); 得到的结果就是一个程序对象，我们可以调用glUseProgram函数，用刚创建的程序对象作为它的参数，以激活这个程序对象： 1glUseProgram(shaderProgram); 在glUseProgram函数调用之后，每个着色器调用和渲染调用都会使用这个程序对象（也就是之前写的着色器)了。 对了，在把着色器对象链接到程序对象以后，记得删除着色器对象，我们不再需要它们了： 12glDeleteShader(vertexShader);glDeleteShader(fragmentShader); 现在，我们已经把输入顶点数据发送给了GPU，并指示了GPU如何在顶点和片段着色器中处理它。就快要完成了，但还没结束，OpenGL还不知道它该如何解释内存中的顶点数据，以及它该如何将顶点数据链接到顶点着色器的属性上。我们需要告诉OpenGL怎么做。 链接顶点属性 见learnopengl 顶点数组对象 如果你在VBO中既有点的位置信息，又有他们的纹理或者颜色信息。 那么就需要用VAO来管理这些不同的属性(Attribute) VAO的作用就是告诉opengl在第个属性在VBO当中是如何存储的 #include &lt;glad/glad.h&gt;#include &lt;GLFW/glfw3.h&gt;#include &lt;iostream&gt;void framebuffer_size_callback(GLFWwindow* window, int width, int height);void processInput(GLFWwindow* window);// settingsconst unsigned int SCR_WIDTH = 800;//屏幕宽度const unsigned int SCR_HEIGHT = 600;//屏幕长度//glsl语法写的Vertex Shaderconst char* vertexShaderSource = "#version 330 core
""layout (location = 0) in vec3 aPos;
""void main()
""{
"" gl_Position = vec4(aPos.x, aPos.y, aPos.z, 1.0);
""}\0";//glsl语法写的Fragment Shaderconst char* fragmentShaderSource = "#version 330 core
""out vec4 FragColor;
""void main()
""{
"" FragColor = vec4(1.0f, 0.5f, 0.2f, 1.0f);
""}
\0";int main(){ // glfw: initialize and configure // ------------------------------ glfwInit(); //OpenGL版本号3.3 glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3); glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3); glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);#ifdef __APPLE__ glfwWindowHint(GLFW_OPENGL_FORWARD_COMPAT, GL_TRUE);#endif // glfw window creation // -------------------- GLFWwindow* window = glfwCreateWindow(SCR_WIDTH, SCR_HEIGHT, "LearnOpenGL", NULL, NULL);//创建窗口对象 if (window == NULL) { std::cout &lt;&lt; "Failed to create GLFW window" &lt;&lt; std::endl; glfwTerminate(); return -1; } glfwMakeContextCurrent(window);//将当前这个窗口设置为OpenGLContext glfwSetFramebufferSizeCallback(window, framebuffer_size_callback);//要注册这个函数，告诉GLFW我们希望每当窗口调整大小的时候调用这个函数 // glad: load all OpenGL function pointers // --------------------------------------- if (!gladLoadGLLoader((GLADloadproc)glfwGetProcAddress))//初始化glad { std::cout &lt;&lt; "Failed to initialize GLAD" &lt;&lt; std::endl; return -1; } // build and compile our shader program // ------------------------------------ // vertex shader //用id来调用Vertex Shader，首选创建一个VERTEX SHADER类型的Shader unsigned int vertexShader = glCreateShader(GL_VERTEX_SHADER); //然后将之前写的Shader glsl源码绑定到现在创建的Shader id上 glShaderSource(vertexShader, 1, &amp;vertexShaderSource, NULL); glCompileShader(vertexShader);//编译Shader // check for shader compile errors int success; char infoLog[512]; glGetShaderiv(vertexShader, GL_COMPILE_STATUS, &amp;success); if (!success) { glGetShaderInfoLog(vertexShader, 512, NULL, infoLog); std::cout &lt;&lt; "ERROR::SHADER::VERTEX::COMPILATION_FAILED
" &lt;&lt; infoLog &lt;&lt; std::endl; } // fragment shader unsigned int fragmentShader = glCreateShader(GL_FRAGMENT_SHADER); glShaderSource(fragmentShader, 1, &amp;fragmentShaderSource, NULL); glCompileShader(fragmentShader); // check for shader compile errors glGetShaderiv(fragmentShader, GL_COMPILE_STATUS, &amp;success); if (!success) { glGetShaderInfoLog(fragmentShader, 512, NULL, infoLog); std::cout &lt;&lt; "ERROR::SHADER::FRAGMENT::COMPILATION_FAILED
" &lt;&lt; infoLog &lt;&lt; std::endl; } // link shaders unsigned int shaderProgram = glCreateProgram();//创建一个着色器程序对象（返回id） glAttachShader(shaderProgram, vertexShader); glAttachShader(shaderProgram, fragmentShader); glLinkProgram(shaderProgram);//先附加再链接 // check for linking errors glGetProgramiv(shaderProgram, GL_LINK_STATUS, &amp;success); if (!success) { glGetProgramInfoLog(shaderProgram, 512, NULL, infoLog); std::cout &lt;&lt; "ERROR::SHADER::PROGRAM::LINKING_FAILED
" &lt;&lt; infoLog &lt;&lt; std::endl; } glDeleteShader(vertexShader);//附加到程序之后可以删除 glDeleteShader(fragmentShader); // set up vertex data (and buffer(s)) and configure vertex attributes // ------------------------------------------------------------------ float vertices[] = { -0.5f, -0.5f, 0.0f, // left 0.5f, -0.5f, 0.0f, // right 0.0f, 0.5f, 0.0f // top }; unsigned int VBO, VAO; glGenVertexArrays(1, &amp;VAO); glGenBuffers(1, &amp;VBO); // bind the Vertex Array Object first, then bind and set vertex buffer(s), and then configure vertex attributes(s). glBindVertexArray(VAO); // 2. 把顶点数组复制到缓冲中供OpenGL使用 glBindBuffer(GL_ARRAY_BUFFER, VBO); glBufferData(GL_ARRAY_BUFFER, sizeof(vertices), vertices, GL_STATIC_DRAW); // 3. 设置顶点属性指针 glVertexAttribPointer(0, 3, GL_FLOAT, GL_FALSE, 3 * sizeof(float), (void*)0); //第一个0对应Vertex Shader源码中的position 0 //最后一个0是offset（偏移量） glEnableVertexAttribArray(0);//启用VAO 属性0（第一个Attribute） // note that this is allowed, the call to glVertexAttribPointer registered VBO as the vertex attribute's bound vertex buffer object so afterwards we can safely unbind glBindBuffer(GL_ARRAY_BUFFER, 0); // You can unbind the VAO afterwards so other VAO calls won't accidentally modify this VAO, but this rarely happens. Modifying other // VAOs requires a call to glBindVertexArray anyways so we generally don't unbind VAOs (nor VBOs) when it's not directly necessary. glBindVertexArray(0); // uncomment this call to draw in wireframe polygons. //glPolygonMode(GL_FRONT_AND_BACK, GL_LINE); // render loop // ----------- while (!glfwWindowShouldClose(window)) { // input // ----- processInput(window);//如果按下esc键将glfwWindowShouldClose状态调整为true // render // ------ glClearColor(0.2f, 0.3f, 0.3f, 1.0f);//设置清空颜色缓冲所用的颜色 glClear(GL_COLOR_BUFFER_BIT);//清除上一次残留的缓存 // draw our first triangle glUseProgram(shaderProgram); glBindVertexArray(VAO); // seeing as we only have a single VAO there's no need to bind it every time, but we'll do so to keep things a bit more organized glDrawArrays(GL_TRIANGLES, 0, 3); // glBindVertexArray(0); // no need to unbind it every time // glfw: swap buffers and poll IO events (keys pressed/released, mouse moved etc.) // ------------------------------------------------------------------------------- glfwSwapBuffers(window);//交换颜色缓冲 glfwPollEvents();//检查有没有触发什么事件（比如键盘输入、鼠标移动等）、更新窗口状态，并调用对应的回调函数（可以通过回调方法手动设置）。 } // optional: de-allocate all resources once they've outlived their purpose: // ------------------------------------------------------------------------ glDeleteVertexArrays(1, &amp;VAO); glDeleteBuffers(1, &amp;VBO); glDeleteProgram(shaderProgram); // glfw: terminate, clearing all previously allocated GLFW resources. // ------------------------------------------------------------------ glfwTerminate();//终止 return 0;}// process all input: query GLFW whether relevant keys are pressed/released this frame and react accordingly// ---------------------------------------------------------------------------------------------------------void processInput(GLFWwindow* window){ if (glfwGetKey(window, GLFW_KEY_ESCAPE) == GLFW_PRESS) glfwSetWindowShouldClose(window, true);}// glfw: whenever the window size changed (by OS or user resize) this callback function executes// ---------------------------------------------------------------------------------------------void framebuffer_size_callback(GLFWwindow* window, int width, int height){ // make sure the viewport matches the new window dimensions; note that width and // height will be significantly larger than specified on retina displays. glViewport(0, 0, width, height);//设置窗口大小}
